args.sparql:
SELECT ?person ?name WHERE {
  ?person wdt:P106 wd:Q161453 .
  ?person wdt:P569 ?birthDate .
  OPTIONAL { ?person wdt:P570 ?deathDate }
  FILTER (!BOUND(?deathDate)) .
  ?person rdfs:label ?name .
  FILTER (lang(?name) = 'en')
} ORDER BY ASC(?birthDate) LIMIT 1

SELECT ?person ?name WHERE {
  ?person wdt:P106 wd:Q161453 .
  ?person wdt:P569 ?birthDate .
  OPTIONAL { ?person wdt:P570 ?deathDate }
  FILTER (!BOUND(?deathDate))
  ?person rdfs:label ?name .
  FILTER (lang(?name) = 'en')
} ORDER BY ASC(?birthDate) LIMIT 1

SELECT ?person ?name WHERE {
  ?person wdt:P106 wd:Q161453 .
  ?person wdt:P569 ?birthDate .
  FILTER NOT EXISTS { ?person wdt:P570 ?deathDate }
  ?person rdfs:label ?name .
  FILTER (lang(?name) = 'en')
}
ORDER BY ASC(?birthDate)
LIMIT 1
